import{_ as t,c as i,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Appendix: Reference Guide | oh-my-opencode","description":"Master oh-my-opencode configuration options, Claude Code compatibility, and built-in MCP servers. This reference covers migration steps and search capabilities to customize your OpenCode environment and extend AI workflows.","frontmatter":{"title":"Appendix: Reference Guide | oh-my-opencode","sidebarTitle":"Appendix","subtitle":"Appendix: Reference Guide and Compatibility","description":"Master oh-my-opencode configuration options, Claude Code compatibility, and built-in MCP servers. This reference covers migration steps and search capabilities to customize your OpenCode environment and extend AI workflows.","tags":["Appendix","Reference"],"order":170},"headers":[],"relativePath":"code-yeongyu/oh-my-opencode/appendix/index.md","filePath":"code-yeongyu/oh-my-opencode/appendix/index.md"}'),n={name:"code-yeongyu/oh-my-opencode/appendix/index.md"};function r(s,e,d,l,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="appendix-reference-guide-and-compatibility" tabindex="-1">Appendix: Reference Guide and Compatibility <a class="header-anchor" href="#appendix-reference-guide-and-compatibility" aria-label="Permalink to &quot;Appendix: Reference Guide and Compatibility&quot;">​</a></h1><p>This chapter contains detailed reference materials and compatibility guidelines for <strong>oh-my-opencode</strong>, covering complete configuration documentation, Claude Code migration support, and detailed introductions to built-in extension servers.</p><h2 id="chapter-contents" tabindex="-1">Chapter Contents <a class="header-anchor" href="#chapter-contents" aria-label="Permalink to &quot;Chapter Contents&quot;">​</a></h2><p>This chapter includes three important sections:</p><table tabindex="0"><thead><tr><th>Subpage</th><th>Description</th><th>Difficulty</th></tr></thead><tbody><tr><td><a href="./claude-code-compatibility/">Claude Code Compatibility</a></td><td>Complete guide for migrating from Claude Code to OpenCode, including compatibility mechanisms for Commands, Skills, Agents, MCPs, and Hooks</td><td>⭐⭐</td></tr><tr><td><a href="./configuration-reference/">Configuration Reference</a></td><td>Complete Schema documentation for oh-my-opencode configuration files, covering all fields, types, and default values</td><td>⭐⭐⭐</td></tr><tr><td><a href="./builtin-mcps/">Built-in MCPs</a></td><td>Features and usage of 3 built-in MCP servers (Exa Websearch, Context7, Grep.app)</td><td>⭐⭐</td></tr></tbody></table><h2 id="recommended-learning-paths" tabindex="-1">Recommended Learning Paths <a class="header-anchor" href="#recommended-learning-paths" aria-label="Permalink to &quot;Recommended Learning Paths&quot;">​</a></h2><p>Choose your learning order based on your needs:</p><h3 id="path-1-migrating-from-claude-code" tabindex="-1">Path 1: Migrating from Claude Code <a class="header-anchor" href="#path-1-migrating-from-claude-code" aria-label="Permalink to &quot;Path 1: Migrating from Claude Code&quot;">​</a></h3><p>If you&#39;re a user migrating from Claude Code:</p><ol><li>First read <strong><a href="./claude-code-compatibility/">Claude Code Compatibility</a></strong> to understand how to seamlessly migrate your existing configuration</li><li>Then review <strong><a href="./configuration-reference/">Configuration Reference</a></strong> to gain deeper understanding of available configuration options</li><li>Finally learn about <strong><a href="./builtin-mcps/">Built-in MCPs</a></strong> to understand how to configure additional search capabilities</li></ol><h3 id="path-2-deep-customization" tabindex="-1">Path 2: Deep Customization <a class="header-anchor" href="#path-2-deep-customization" aria-label="Permalink to &quot;Path 2: Deep Customization&quot;">​</a></h3><p>If you wish to deeply customize oh-my-opencode behavior:</p><ol><li>Start with <strong><a href="./configuration-reference/">Configuration Reference</a></strong> to understand all configurable items</li><li>Learn about <strong><a href="./builtin-mcps/">Built-in MCPs</a></strong> to configure search and documentation query capabilities</li><li>Reference <strong><a href="./claude-code-compatibility/">Claude Code Compatibility</a></strong> to understand compatibility layer configuration options</li></ol><h3 id="path-3-quick-reference" tabindex="-1">Path 3: Quick Reference <a class="header-anchor" href="#path-3-quick-reference" aria-label="Permalink to &quot;Path 3: Quick Reference&quot;">​</a></h3><p>If you only need to look up specific information:</p><ul><li><strong>Configuration questions</strong> → Go directly to <strong><a href="./configuration-reference/">Configuration Reference</a></strong></li><li><strong>Migration questions</strong> → Go directly to <strong><a href="./claude-code-compatibility/">Claude Code Compatibility</a></strong></li><li><strong>MCP configuration</strong> → Go directly to <strong><a href="./builtin-mcps/">Built-in MCPs</a></strong></li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>For this chapter, it&#39;s recommended that you have already:</p><ul><li>✅ Completed <strong><a href="./../start/installation/">Installation &amp; Configuration</a></strong></li><li>✅ Understood the basic concepts of <strong><a href="./../start/sisyphus-orchestrator/">Sisyphus Orchestrator</a></strong></li><li>✅ Familiarity with editing JSON configuration files</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can:</p><ul><li>🚀 Try <strong><a href="./../advanced/">Advanced Features</a></strong> to learn more advanced usage</li><li>🔧 Check <strong><a href="./../faq/">FAQ</a></strong> to resolve usage issues</li><li>📖 Read <strong><a href="./../changelog/">Changelog</a></strong> to stay updated on new feature improvements</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>The content in this chapter primarily serves as reference material and doesn&#39;t need to be read sequentially. You can consult relevant sections as needed.</p></div>',23)])])}const f=t(n,[["render",r]]);export{h as __pageData,f as default};
